Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              <PLACEHOLDER>
              else if(end && end !== true) {
                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-                 if(done) done(end === true ? null : end)
In the mutated code, <PLACEHOLDER> has the value:

+                 if(true) done(end === true ? null : end)


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-79747e0/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is:
- Original: `if(done) done(end === true ? null : end)` 
- Mutated: `if(true) done(end === true ? null : end)`

The difference is that in the original, `done` is only called if it exists (truthy check). In the mutated version, `done` is always called regardless of whether it was provided, which would throw an error if `done` is `undefined`.

So the test should call `drain` without a `done` callback and verify it doesn't throw an error when the stream ends normally.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain without done callback", () => {
  it("should not throw when stream ends normally and no done callback is provided", (done) => {
    // Create a simple readable source that emits one value then ends
    let count = 0;
    const source = (end: any, cb: (end: any, data?: any) => void) => {
      if (end) return cb(end, null);
      if (count === 0) {
        count++;
        cb(null, "data");
      } else {
        cb(true, null); // end of stream
      }
    };

    // Call drain without a done callback - original should handle this gracefully
    // Mutated code will try to call undefined as a function, throwing a TypeError
    let threw = false;
    try {
      const sink = drain(null);
      sink(source);
      // Give it a tick to process
      setTimeout(() => {
        expect(threw).toBe(false);
        done();
      }, 10);
    } catch (e) {
      threw = true;
      // Original code should not throw, mutated code will throw TypeError
      done(e);
    }
  });
});
```

Wait, the issue is that the error might be thrown asynchronously inside the callback. Let me reconsider and write a test that properly catches the async error.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain without done callback", () => {
  it("should not throw when stream ends and no done callback is provided", (done) => {
    let count = 0;
    const source = (end: any, cb: (end: any, data?: any) => void) => {
      if (end) return cb(end, null);
      if (count === 0) {
        count++;
        cb(null, "data");
      } else {
        cb(true, null);
      }
    };

    // In the mutated code, calling done() when done is undefined will throw TypeError
    // We capture uncaught exceptions to detect this
    const originalHandler = process.listeners("uncaughtException").slice();
    let errorCaught: Error | null = null;

    const errorHandler = (err: Error) => {
      errorCaught = err;
    };
    process.once("uncaughtException", errorHandler);

    const sink = drain(null);
    sink(source);

    setTimeout(() => {
      process.removeListener("uncaughtException", errorHandler);
      // Original: no error (done is undefined, so if(done) is false, done() not called)
      // Mutated: TypeError because done is undefined but if(true) tries to call it
      expect(errorCaught).toBeNull();
      done();
    }, 50);
  });
});
```
